import os
import json
from flask import Flask, request, session, redirect, url_for, render_template, make_response
from onelogin.saml2.auth import OneLogin_Saml2_Auth
from onelogin.saml2.settings import OneLogin_Saml2_Settings
from onelogin.saml2.utils import OneLogin_Saml2_Utils

# Helper function to prepare Flask request for python3-saml library
def prepare_flask_request(request):
    url_data = OneLogin_Saml2_Utils.parse_url(request.url)
    return {
        'https': 'on' if request.scheme == 'https' else 'off',
        'http_host': request.host,
        'server_port': url_data['port'],
        'script_name': request.path,
        'get_data': request.args.copy(),
        'post_data': request.form.copy(),
        'query_string': request.query_string.decode('utf-8')
    }

# Helper function to initialize SAML auth object
def init_saml_auth(req):
    # 'saml_settings' is the directory where settings.json and advanced_settings.json are located
    auth = OneLogin_Saml2_Auth(req, custom_base_path=os.path.join(os.path.dirname(__file__), 'saml_settings'))
    return auth

app = Flask(__name__)
# IMPORTANT: Change this to a strong, random secret key in production!
app.secret_key = 'your_super_secret_key_here_replace_me' 

# This function ensures SAML settings are loaded with SP certs
def get_saml_settings():
    base_path = os.path.join(os.path.dirname(__file__), 'saml_settings')
    settings_file_path = os.path.join(base_path, 'settings.json')
    advanced_settings_file_path = os.path.join(base_path, 'advanced_settings.json')

    with open(settings_file_path, 'r') as f:
        settings = json.load(f)
    with open(advanced_settings_file_path, 'r') as f:
        advanced_settings = json.load(f)

    # Load SP certificate and private key from files
    sp_cert_path = os.path.join(base_path, 'sp.crt')
    sp_key_path = os.path.join(base_path, 'sp.key')
    with open(sp_cert_path, 'r') as f:
        settings['sp']['x509cert'] = f.read()
    with open(sp_key_path, 'r') as f:
        settings['sp']['privateKey'] = f.read()

    # The OneLogin_Saml2_Settings object handles loading advanced settings
    saml_settings = OneLogin_Saml2_Settings(settings, advanced_settings_file=advanced_settings_file_path)
    return saml_settings

# Load SAML settings once at app startup
SAML_SETTINGS = get_saml_settings()

@app.route('/')
def index():
    if 'samlUserdata' in session:
        return redirect(url_for('dashboard'))
    return render_template('index.html')

@app.route('/login')
def login():
    req = prepare_flask_request(request)
    auth = init_saml_auth(req)
    
    # Generate the SAMLAuthNRequest and redirect to the IdP's SSO URL
    return redirect(auth.login())

@app.route('/saml/acs', methods=['POST'])
def acs():
    req = prepare_flask_request(request)
    auth = init_saml_auth(req)
    
    # Process the SAML Response from the IdP
    # The 'process_response' method handles all SAML validation,
    # including signature validation if 'wantAssertionsSigned' is true in settings.
    auth.process_response()
    
    errors = auth.get_errors()
    if len(errors) == 0:
        if auth.is_authenticated():
            # User is authenticated. Extract attributes.
            session['samlUserdata'] = auth.get_attributes()
            session['samlNameId'] = auth.get_nameid()
            session['samlSessionIndex'] = auth.get_session_index()
            # If the IdP provides a session_not_on_or_after, store it
            session['samlSessionNotOnOrAfter'] = auth.get_session_not_on_or_after()

            print("SAML Authentication Successful!")
            print(f"NameID: {session['samlNameId']}")
            print(f"Attributes: {session['samlUserdata']}")

            # Redirect to the dashboard or original RelayState
            return redirect(url_for('dashboard'))
        else:
            # Not authenticated, but no errors from process_response
            # This can happen if the IdP sends an authentication failure response
            print(f"Authentication failed: {auth.get_last_error_reason()}")
            return f"Authentication failed: {auth.get_last_error_reason()}", 401
    else:
        # Errors occurred during SAML response processing
        error_reason = auth.get_last_error_reason()
        print(f"SAML Response error: {error_reason} (Errors: {', '.join(errors)})")
        return f"SAML Response error: {error_reason} (Errors: {', '.join(errors)})", 400

@app.route('/saml/metadata')
def saml_metadata():
    req = prepare_flask_request(request)
    auth = init_saml_auth(req)
    settings = auth.get_settings()
    
    # Generate the SP's metadata XML
    metadata = settings.get_sp_metadata()
    errors = settings.validate_metadata(metadata)

    if len(errors) == 0:
        resp = make_response(metadata, 200)
        resp.headers['Content-Type'] = 'text/xml'
    else:
        resp = make_response(f"Error validating SP metadata: {', '.join(errors)}", 500)
    return resp

@app.route('/dashboard')
def dashboard():
    if 'samlUserdata' not in session:
        return redirect(url_for('index'))
    
    user_data = session['samlUserdata']
    name_id = session['samlNameId']
    
    # Display extracted SAML attributes
    return render_template('dashboard.html', user_data=user_data, name_id=name_id)

@app.route('/logout')
def logout():
    # Clear the session data
    session.clear()
    return redirect(url_for('index'))

